import{_ as a,o as e,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"하네스 엔지니어링의 의의","description":"","frontmatter":{},"headers":[],"relativePath":"part3-harness/index.md","filePath":"part3-harness/index.md"}'),s={name:"part3-harness/index.md"};function n(l,t,i,d,h,c){return e(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="하네스-엔지니어링의-의의" tabindex="-1">하네스 엔지니어링의 의의 <a class="header-anchor" href="#하네스-엔지니어링의-의의" aria-label="Permalink to &quot;하네스 엔지니어링의 의의&quot;">​</a></h1><h2 id="패러다임의-전환" tabindex="-1">패러다임의 전환 <a class="header-anchor" href="#패러다임의-전환" aria-label="Permalink to &quot;패러다임의 전환&quot;">​</a></h2><p>하네스 엔지니어링은 단순한 도구의 발전이 아니라, <strong>&quot;AI를 어떻게 활용할 것인가&quot;에 대한 근본적인 사고방식의 전환</strong>입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>과거: &quot;AI를 잘 쓰는 개인의 기술&quot;</span></span>
<span class="line"><span>현재: &quot;AI 팀을 잘 설계하는 조직의 역량&quot;</span></span></code></pre></div><h2 id="누구에게-의미가-있는가" tabindex="-1">누구에게 의미가 있는가? <a class="header-anchor" href="#누구에게-의미가-있는가" aria-label="Permalink to &quot;누구에게 의미가 있는가?&quot;">​</a></h2><h3 id="개발자에게" tabindex="-1">개발자에게 <a class="header-anchor" href="#개발자에게" aria-label="Permalink to &quot;개발자에게&quot;">​</a></h3><table tabindex="0"><thead><tr><th>변화</th><th>Before (2세대)</th><th>After (3세대)</th></tr></thead><tbody><tr><td>코드 품질</td><td>AI가 생성한 코드를 일일이 검토</td><td>QA 에이전트가 자동 리뷰</td></tr><tr><td>아키텍처</td><td>매번 구조를 설명해야 함</td><td>스킬에 아키텍처 패턴이 내장</td></tr><tr><td>일관성</td><td>대화마다 스타일이 달라짐</td><td>워크플로우가 일관성 보장</td></tr><tr><td>온보딩</td><td>새 프로젝트마다 처음부터 설정</td><td><code>.agents/</code> 폴더 복사하면 끝</td></tr></tbody></table><h3 id="비개발자에게" tabindex="-1">비개발자에게 <a class="header-anchor" href="#비개발자에게" aria-label="Permalink to &quot;비개발자에게&quot;">​</a></h3><ul><li><strong>기획자/PM</strong>: 워크플로우(<code>/plan</code>)로 체계적인 기획 → 구현 연결</li><li><strong>디자이너</strong>: 디자인 에이전트가 디자인 시스템을 코드와 동기화</li><li><strong>관리자</strong>: AI 활용의 <strong>표준화</strong>와 <strong>재현 가능성</strong> 확보</li></ul><h3 id="조직에게" tabindex="-1">조직에게 <a class="header-anchor" href="#조직에게" aria-label="Permalink to &quot;조직에게&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">🏢 조직 차원의 의의</p><ol><li><strong>AI 활용 표준화</strong>: 프로젝트마다 일관된 AI 활용 체계</li><li><strong>온보딩 시간 단축</strong>: 새 팀원이 <code>.agents/</code>만 보면 워크플로우 파악</li><li><strong>품질 게이트 자동화</strong>: 보안, 성능, 접근성 검증이 워크플로우에 내장</li><li><strong>비용 최적화</strong>: 토큰 효율적인 스킬 설계로 API 비용 절감</li><li><strong>벤더 독립성</strong>: 특정 AI 도구에 종속되지 않는 이식 가능한 체계</li></ol></div><h2 id="왜-엔지니어링-인가" tabindex="-1">왜 &quot;엔지니어링&quot;인가? <a class="header-anchor" href="#왜-엔지니어링-인가" aria-label="Permalink to &quot;왜 &quot;엔지니어링&quot;인가?&quot;">​</a></h2><p>단순히 도구를 설치하는 것이 아니라, <strong>설계가 필요</strong>하기 때문입니다:</p><ul><li>어떤 에이전트가 필요한가?</li><li>각 에이전트에게 어떤 스킬을 부여할 것인가?</li><li>워크플로우를 어떤 순서로 구성할 것인가?</li><li>품질 게이트를 어디에 배치할 것인가?</li></ul><p>이 <strong>설계 역량</strong>이 바이브 코딩의 결과를 결정합니다.</p>`,15)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
